def calculate_discount(user_role):
    if user_role == 'enterprise':
        return 0.30
    elif user_role == 'premium':
        return 0.15
    else:
        return 0.00

def process_payment(cart_total, discount_percentage):
    discounted_amount = cart_total * (1 - discount_percentage)
    print(f"Discounted Total: ${discounted_amount:.2f}")
    # Simulate payment processing
    print("Payment processed successfully.")

def payment_processing_function(user, cart_items, payment_details):
    user_role = user.role
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    discount_percentage = calculate_discount(user_role)
    process_payment(cart_total, discount_percentage)

